```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input buffer
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer_copy);

    NetworkPacket packet;

    // Read packet_id using read() function
    adaptor.read(&packet.packet_id, sizeof(packet.packet_id));

    // Read username using prefixed string reading
    adaptor.read_prefixed(packet.username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.read_container(packet.scores, score_count);

    // Read metadata as null-terminated string
    adaptor.read_null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    size_t remaining_bytes = adaptor.write_ - adaptor.read_;
    if (remaining_bytes > 0) {
        adaptor.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input buffer
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer_copy);

    PacketInfo info;

    // Use span() for packet_id to get zero-copy view
    auto packet_id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *packet_id_span.data();

    // Read username using prefixed adaptor to get string_view
    adaptor.read_prefixed(info.username);

    // Skip the scores vector by reading count and skipping data
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

