#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source_buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> ba(source_buffer);

    // Check if the requested bytes_to_read is within the available data
    if (bytes_to_read > ba.size()) {
        throw std::out_of_range("Requested to read more bytes than available in buffer");
    }

    // Create a destination buffer to store the read data
    std::vector<uint8_t> destination(bytes_to_read);

    // Use the read function of buffer_adaptor to copy the data to the destination buffer
    ba.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer_adaptor object from the dest_buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> ba(dest_buffer);

    // Check if there is enough space in the buffer_adaptor to write the source_data
    if (ba.free() < source_data.size()) {
        throw std::overflow_error("Insufficient space in buffer for write operation");
    }

    // Use the write function of buffer_adaptor to write the source_data
    ba.write(source_data.data(), source_data.size());
}
```

