    hexi::buffer_adaptor<const std::vector<uint8_t>> ba(source_buffer);

    // Check if the requested bytes_to_read is within the available data
    if (bytes_to_read > ba.size()) {
        throw std::out_of_range("Requested to read more bytes than available in buffer");
    }

    // Create a destination buffer to store the read data
    std::vector<uint8_t> destination(bytes_to_read);

    // Use the read function of buffer_adaptor to copy the data to the destination buffer
    ba.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
