    BufferData<> result;

    // Read header value from buffer
    buffer.read(&result.header, sizeof(result.header));

    // Create vector with specified length and read data into it
    result.data.resize(data_length);
    if (data_length > 0) {
        buffer.read(result.data.data(), data_length);
    }

    return result;
}
```

