#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Check if the requested number of bytes to peek is greater than the buffer's size
    size_t bytes_to_copy = std::min(bytes_to_peek, buffer.size());

    // Create a vector to hold the peeked data
    std::vector<uint8_t> result(bytes_to_copy);

    // Use the buffer's copy method to copy data without advancing the read pointer
    buffer.copy(result.data(), bytes_to_copy);

    // Return the vector containing the peeked data
    return result;
}
```

