You need to implement a function that demonstrates the free list operations:

`manage_free_blocks`: This function should demonstrate how the block allocator manages its free list internally. Note that `push()` and `pop()` are private methods, but understanding their behavior helps understand how the allocator works.

The `push()` method adds a block to the head of the free list, and `pop()` removes and returns the head block from the free list.

Here is the code to finish the function, please output the complete contents of the file:
```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // TODO: create block_allocator and demonstrate allocation/deallocation
    // which internally uses push() and pop() for free list management
}
```

ground truth:
#include <hexi/allocators/block_allocator.h>
#include <cstdint>

struct test_block {
    std::byte data[1024];
};

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    hexi::block_allocator<test_block, element_count> allocator;

    // Allocate blocks - internally uses pop() to get from free list
    auto* block1 = allocator.allocate();
    auto* block2 = allocator.allocate();

    // Deallocate blocks - internally uses push() to return to free list
    allocator.deallocate(block1);
    allocator.deallocate(block2);

    // Subsequent allocations reuse the freed blocks
    auto* block3 = allocator.allocate();
    auto* block4 = allocator.allocate();

    allocator.deallocate(block3);
    allocator.deallocate(block4);
}

test cases:
#include <gtest/gtest.h>
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <cstddef>
#include <vector>

// Include the implementation
#include "implementation.hpp"

TEST(BlockAllocator, FreeListManagement) {
    demonstrate_block_allocator_behavior<10>();

    // Test passes if no assertion failures occur
    EXPECT_TRUE(true);
}

TEST(BlockAllocator, ReuseFreedBlocks) {
    struct test_block {
        std::byte data[1024];
    };

    hexi::block_allocator<test_block, 5> allocator;

    std::vector<test_block*> blocks;
    for (int i = 0; i < 5; ++i) {
        blocks.push_back(allocator.allocate());
    }

    // Free all blocks
    for (auto* block : blocks) {
        allocator.deallocate(block);
    }

    // Allocate again - should reuse freed blocks
    for (int i = 0; i < 5; ++i) {
        auto* block = allocator.allocate();
        ASSERT_NE(nullptr, block);
        allocator.deallocate(block);
    }
}

