#include <hexi/endian.h>
#include <cstdint>

template<hexi::endian::conversion conv, typename T>
T convert_with_enum(T value) {
    switch (conv) {
        case hexi::endian::conversion::big_to_native:
            return hexi::endian::big_to_native(value);
        case hexi::endian::conversion::native_to_big:
            return hexi::endian::native_to_big(value);
        case hexi::endian::conversion::little_to_native:
            return hexi::endian::little_to_native(value);
        case hexi::endian::conversion::native_to_little:
            return hexi::endian::native_to_little(value);
        default:
            // For completeness, though the enum should only have these four values
            return value;
    }
}
```

