#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a binary_stream object using the buffer
    hexi::binary_stream stream(buffer);

    // Serialize packet_id as a raw integer using operator<<
    stream << packet.packet_id;

    // Use prefixed_varint adaptor for tags vector
    stream << hexi::prefixed_varint(packet.tags);

    // Use prefixed_varint adaptor for data string
    stream << hexi::prefixed_varint(packet.data);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a buffer adaptor for the input buffer
    // Note: Need to create a writable buffer from the span for deserialization
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);

    // Create a binary_stream object using the buffer adaptor
    hexi::binary_stream stream(adaptor);

    // Deserialize packet_id as a raw integer using operator>>
    stream >> packet.packet_id;

    // Use prefixed_varint adaptor to read tags vector
    stream >> hexi::prefixed_varint(packet.tags);

    // Use prefixed_varint adaptor to read data string
    stream >> hexi::prefixed_varint(packet.data);

    return packet;
}
```

