```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (const auto& temp : temperatures) {
            auto converted_temp = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted_temp);
        }

        // Convert and write pressure with runtime endianness conversion
        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read sensor_id directly
        adaptor.read(sensor_id);

        // Read each temperature and convert from little-endian to native
        for (size_t i = 0; i < temperatures.size(); ++i) {
            float temp;
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
            temperatures[i] = temp;
        }

        // Read pressure and convert from little-endian to native
        double p;
        adaptor.read(p);
        hexi::endian::little_to_native_inplace(p);
        pressure = p;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    hexi::Buffer buffer;
    hexi::Stream stream(buffer);
    stream.serialise(data);
    return buffer.data();
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::Buffer buf(buffer.data(), buffer.size());
    hexi::Stream stream(buf);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::Buffer buf(buffer.data(), buffer.size());
    hexi::Stream stream(buf);

    SensorInfo info;

    // Use view to extract null-terminated sensor name string
    info.sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    uint32_t id;
    stream.read(&id, sizeof(id));
    info.sensor_id = id;

    // Skip remaining data using skip
    stream.skip(stream.read_max());

    return info;
}
